insert into programs (id, title, agency, operator, category, track, summary, support_type, support_amount, support_amount_max, apply_start, apply_end, apply_cycle, source_url, as_of_date, verification, fashion_specific, eligibility) values
  ('sfw-2026fw', '2026 F/W 서울패션위크 참가 브랜드', '서울특별시 (경제실 뷰티패션산업과)', '서울패션위크 사무국', '{"해외수출","전시박람회"}', '{"디자이너","기업브랜드"}', '서울패션위크 참가 브랜드로 선정되면 패션쇼 무대(장소·조명·음향·온라인 송출), 국내외 미디어 홍보, B2B 트레이드쇼(바이어 수주상담), 밀라노 현지 세일즈 프로그램 참가를 지원받는다. K-패션의 대표적 해외진출 플랫폼.', '{"전시·쇼","해외세일즈","홍보","B2B상담"}', '패션쇼 개최·트레이드쇼·해외세일즈 프로그램 현물 지원 (현금 지급 아님)', null, null, null, '연 2회 (F/W·S/S)', 'https://www.seoulfashionweek.org', '2026-06-13', 'needs_review', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "디자이너관/기업브랜드관/트레이드쇼 트랙별 자격 상이. 26 F/W 기업브랜드관 신청 2025-11-03~11-28(행사 2026.2 DDP). 트레이드쇼는 의류·잡화 독립 브랜드 업력 1년 이상 필요. 차기 일정·소재지 요건은 모집공고 확인."}'::jsonb),
  ('kfashion-global-popup-2026', 'K-패션 브랜드 글로벌 팝업 지원사업', '서울경제진흥원(SBA)', null, '{"해외수출"}', '{"기업브랜드"}', 'K-패션 브랜드의 해외 팝업스토어 진출을 지원하는 사업. 해외 현지 팝업 운영 비용을 기업당 정액 지원한다.', '{"현금","해외팝업"}', '해외 팝업비 기업당 700만원 (자부담 300만원 이상 매칭 필수)', 7000000, '2026-04-07', '2026-04-27', '연 1회 (추정)', 'https://www.nextunicorn.kr/support-programs/11670c7fe6734835', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": true, "region": ["서울"], "notes": "운영주체 서울경제진흥원(SBA). 신청일 기준 서울 소재 사업장. 2시즌 이상 컬렉션 제작 + 국내외 세일즈 경험, 수출실적증명원(최근 해외매출) 제출 필수. 자부담 300만원 이상 매칭. 2026 모집 4/7~4/27(종료), 차년도 재모집 알림 대상."}'::jsonb),
  ('fashion-amazon-2026', '패션기업 아마존 입점 진출 지원', '서울특별시 (경제실 뷰티패션산업과)', null, '{"해외수출"}', '{"기업브랜드"}', '세계 최대 온라인 커머스 아마존 입점을 통한 해외 온라인 판로 개척 지원. 6주 정규교육(업종별 맞춤)과 입점 달성까지 1:1 컨설팅, 입점 기업에 마케팅·해외물류비를 지원한다.', '{"교육","컨설팅","현금"}', '마케팅·해외물류비 최대 300만원 + 6주 교육 + 1:1 컨설팅', 3000000, null, null, '연 1회 (추정)', 'https://opengov.seoul.go.kr/press/20970652', '2026-06-13', 'needs_review', true, '{"min_years": 1, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["서울"], "notes": "자격(서울 소재·업력 1년 이상)·금액은 2020~21년 공고 기준. 2021 이후 패션 특화 아마존 입점 공고 미확인 — 2026 운영 지속 불명(폐지/통합 가능성). 매칭 노출 시 주의. (2026 아마존 액셀러레이터는 뷰티·건기식 대상의 별개 사업)"}'::jsonb),
  ('ddm-kfashion-2026', '동대문 기반 K-패션 브랜드 육성 (서울패션허브)', '서울특별시 (경제실 뷰티패션산업과)', '서울패션허브', '{"해외수출","디자인개발","국내성장"}', '{"디자이너"}', '동대문 기반 신진 디자이너 브랜드를 대상으로 전문가 밀착 컨설팅, 시제품 개발, 룩북 제작, 국내외 지식재산권(IP) 확보, 판로 다각화를 지원한다. 해외진출은 IP·판로 다각화 일부에 한정.', '{"컨설팅","시제품","IP","판로"}', '공간·컨설팅·시제품·룩북·판로 현물 지원 (디자이너 브랜드 약 40개사)', null, '2026-02-09', '2026-02-27', '연 1회', 'https://www.sfhub.or.kr/bbs/business/143', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["서울"], "notes": "동대문 거점 신진 디자이너 브랜드 약 40개사. 운영 서울패션허브. 2026 디자이너 브랜드 트랙 모집 2/9~2/27(종료). 별도 ''동대문 도매상인 브랜드 육성'' 트랙(2/9~3/8) 존재."}'::jsonb),
  ('kotra-overseas-exhibition-individual-2026', '2026년 해외전시회 개별참가지원 사업', '산업통상자원부', 'KOTRA / 한국전시산업진흥회', '{"해외수출","전시박람회"}', '{"기업브랜드"}', '해외 전문전시회에 기업이 개별 참가할 때 부스 직접비용, 전시품·샘플 운송비, 현지 마케팅 서비스 비용 등을 사후 실비로 보전한다. 패션·소비재 기업이 단독 부스로 참가할 때 활용 가능.', '{"현금","전시·쇼"}', '기업당 연 1회, 최대 600만원 한도로 부스비·운송비·마케팅비 등 사후 실비 지원', 6000000, '2025-11-21', '2025-12-05', '연 1회', 'https://www.bizinfo.go.kr/sii/siia/selectSIIA200Detail.do?pblancId=PBLN_000000000116467', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["법인", "개인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "국내 중소·중견기업. 비목별 한도는 KOTRA 무역투자24 원문 확인 필요. 2025-12-05 마감분은 종료, 다음 회차 일정 확인 필요."}'::jsonb),
  ('kotra-overseas-branch-2026', '2026년 해외지사화사업', '산업통상자원부', 'KOTRA / 중진공 / OKTA', '{"해외수출"}', '{"기업브랜드"}', '해외 지사를 직접 둘 여력이 부족한 기업을 위해 KOTRA 해외무역관 등이 현지 지사 역할을 대행한다. 바이어 발굴, 수출성약, 전시·상담회, 물류·통관 자문을 진입·발전·확장 단계로 지원.', '{"해외세일즈","바이어매칭","컨설팅"}', '단계별 현지 마케팅 대행. 기업부담금: 진입(OKTA) 6개월 약 100만원, 발전(KOTRA) 150~360만원·중진공 225~375만원, 확장(중진공) 9개월 약 600만원', null, '2026-01-07', '2026-01-16', '연 복수회 (차수별)', 'https://www.kotra.or.kr', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["법인", "개인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중소·중견기업(휴·폐업 제외). KOTRA·중진공·OKTA 통합 운영, 전 업종(패션 포함). 2026 연 복수 차수(1차 1/7~1/16, 4차 3/25~4/10). 수출바우처로 부담금 납부 불가. 단계별 부담금은 2026 공식 사업안내 기준."}'::jsonb),
  ('export-voucher-2026', '2026년 수출바우처 (수출지원기반활용사업)', '중소벤처기업부 / 산업통상자원부 (부처별 분리 공고)', 'KOSME / KOTRA', '{"해외수출"}', '{"기업브랜드"}', '선정 기업이 바우처 한도 내에서 전시회·홍보·디자인·통번역·인증·바이어 발굴 등 14대 메뉴 서비스를 자율 선택해 사용하고 정산하는 우산형(메뉴판식) 지원사업. 전년 수출액 규모로 단계를 나눠 차등 지원. 패션·소비재 브랜드의 해외 마케팅·디자인 개발에 가장 널리 쓰이는 사업.', '{"바우처","현금","컨설팅","전시·쇼","해외세일즈"}', '전년 수출실적 단계별 차등 — 내수·초보 ~3,000만원, 유망 ~4,500만원, 성장 ~7,000만원, 강소 ~1억원. 국고보조율 단계·소관(중기부/산업부)별 상이', 100000000, '2025-12-17', '2026-01-09', '연 복수 차수', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000116842', '2026-06-13', 'needs_review', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중소기업기본법 제2조 중소기업. 일정·자격 2026 확인(1차 2025-12-17~2026-01-09, 연중 추가 차수). 수출실적은 자격이 아니라 지원금액 단계 결정 변수(수출 0원도 내수단계 신청 가능). ⚠️단계별 한도는 출처마다 상이 — 당해 공고 원문(PDF) 재확인 필요. 중기부 소관은 업종 제한 적음(패션 가능), 산업부 소관은 제한 있음."}'::jsonb),
  ('kita-kpremium-global-retail-popup-2026', 'K-프리미엄 소비재 글로벌 대형유통망 진출사업', '한국무역협회(KITA)', '현대백화점 / 메디쿼터스', '{"해외수출","전시박람회"}', '{"기업브랜드","디자이너"}', '무역협회가 현대백화점·메디쿼터스와 협업해 일본·대만 등 해외 대형 쇼핑몰에 K-패션·K-뷰티 팝업스토어를 마련하고 국내 기업의 현지 판매·인지도 제고를 지원.', '{"공간","전시·쇼","해외세일즈"}', '해외 5개 대형 쇼핑몰 팝업, 약 40개사 참여, 2026년 3~12월 운영. 현금 지원 규모 미공개', null, null, null, null, 'https://www.thebk.co.kr/news/articleView.html?idxno=305278', '2026-06-13', 'needs_review', false, '{"min_years": null, "max_years": null, "biz_type": ["법인", "개인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "현대백화점·메디퀘스트 3자 MOU, 일본·대만 등 대형쇼핑몰 약 40개사(패션·뷰티). 2026 참가기업 모집 ~1/7 마감(종료), 팝업 운영 2026.3~12. 업력·지역·수출·금액은 공고 본문 미명시."}'::jsonb),
  ('tradekorea-kita-online-marketing-2026', 'tradeKorea 온라인 수출마케팅 지원', '한국무역협회(KITA)', 'tradeKorea.com', '{"해외수출"}', '{"기업브랜드"}', '무역협회가 운영하는 글로벌 B2B 플랫폼 tradeKorea를 통해 상품 등록, 해외 바이어 매칭, 거래 알선, 홍보영상 제작, 인플루언서 마케팅, 글로벌 이커머스 입점을 지원. 온라인 해외 판로 개척에 활용.', '{"바이어매칭","해외세일즈","교육"}', '플랫폼 입점·바이어 매칭 무료, 영상·콘텐츠·인플루언서 마케팅 등 부가 지원은 사업별 상이', null, null, null, '상시', 'https://kr.tradekorea.com/kr/marketing/contents/info.do', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["법인", "개인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "KITA 운영 B2B 플랫폼(tradeKorea). 플랫폼 입점·바이어 매칭 무료, 월별 유망 바이어 매칭 등 상시. 부가 마케팅 지원은 사업별 상이."}'::jsonb),
  ('kita-overseas-marketing-buyer-matching-2026', 'KITA 해외마케팅 사업 (수출상담회·바이어 매칭)', '한국무역협회(KITA)', null, '{"해외수출","전시박람회"}', '{"기업브랜드"}', '무역협회가 연간 운영하는 해외마케팅 사업으로 해외 전시회 단체관, 수출상담회·바이어 매칭, 무역사절단, 해외 팝업 등으로 중소 수출기업의 판로 개척을 지원. 패션·소비재 프로그램 포함.', '{"바이어매칭","전시·쇼","해외세일즈","공간"}', null, null, null, null, '연중 (프로그램별 상이)', 'https://www.kita.net/mberJobSport/bsnsReqstSchdul/cmmrcSportBsnsCldr/cmmrcSportBsnsSchdul/cmmrcSportBsnsSchdulList.do', '2026-06-13', 'needs_review', false, '{"min_years": null, "max_years": null, "biz_type": ["법인", "개인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "단일 사업이 아닌 KITA B2B 해외마케팅·바이어매칭 사업군 총칭(수출상담회·무역사절단 등 개별 공고 다수). 프로그램별 일정·자격·참가비 상이 — kita.net 개별 확인."}'::jsonb),
  ('kocca-concept-korea-paris-fashionweek', '컨셉코리아(Concept Korea) 파리패션위크 참가브랜드 지원', '문화체육관광부', '한국콘텐츠진흥원(KOCCA)', '{"해외수출","전시박람회"}', '{"디자이너"}', '국내 디자이너패션 브랜드를 선발해 파리패션위크 시즌별(S/S·F/W) 패션쇼를 개최하고 국내외 비즈니스·홍보를 지원하는 K-패션 해외진출 대표 사업. 2024년부터 파리패션위크 공식 프로그램으로 진행.', '{"전시·쇼","해외세일즈","바이어매칭"}', '파리 패션쇼 개최 및 국내외 비즈니스·홍보 지원 (구체 금액 미확인)', null, '2025-04-29', '2025-05-20', '연 1회 (시즌 모집)', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000108709', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "국내 디자이너패션 브랜드. 선발 자격·업력 요건은 공고 확인 필요. 2025 모집은 2026 시즌 기준."}'::jsonb),
  ('kocca-fashion-design-prototype-2025', '패션디자인 시제품 제작지원 (KOCCA 패션 부문)', '문화체육관광부', '한국콘텐츠진흥원(KOCCA)', '{"디자인개발","국내성장"}', '{"디자이너"}', '국내 패션 디자이너 브랜드의 시제품(샘플) 제작비·재료비·홍보비를 지원해 브랜드 경쟁력과 시장 진출 기반을 마련. 일반의류와 패션잡화 부문으로 구분.', '{"현금","전시·쇼"}', '일반의류 최대 5,100만원(15개 내외), 패션잡화 최대 2,750만원(2개 내외)', 51000000, '2025-02-24', '2025-03-17', '연 1회', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000105220', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "한국 국적 디자이너 브랜드, 4시즌 이상 컬렉션 제작·세일즈 경험 보유. 직접 해외수출보다 디자인개발 성격. 2026 공고 확인 필요."}'::jsonb),
  ('kocca-sustainable-fashion-2025', '지속가능패션 제작지원 (KOCCA 패션 부문)', '문화체육관광부', '한국콘텐츠진흥원(KOCCA)', '{"디자인개발","국내성장"}', '{"디자이너","기업브랜드"}', '환경·사회·경제·문화적 실천을 수행하는 국내 패션 브랜드의 지속가능 제품 제작을 지원. 초기부문과 일반부문으로 구분.', '{"현금"}', '일반부문 의류 최대 7,000만원·잡화 최대 3,500만원, 초기부문 의류 최대 5,000만원·잡화 최대 2,300만원', 70000000, '2025-02-24', '2025-03-17', '연 1회', 'https://sfsc.or.kr/anews', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "지속가능성 실천 국내 브랜드. 초기/일반 부문 구분 자격은 공고 확인 필요."}'::jsonb),
  ('kfa-global-marketing-2025', '글로벌 마케팅 지원 (K-섬유패션 스트림 글로벌 브랜드 육성)', '산업통상자원부', '한국패션산업협회(KFA)', '{"해외수출","전시박람회"}', '{"기업브랜드","디자이너"}', '해외 진출을 원하는 국내 패션 브랜드의 해외 전시 참가와 글로벌 쇼룸 온·오프라인 입점 등 B2B 마케팅을 지원. 전년도 30여개 브랜드가 약 65억원 수출 달성.', '{"전시·쇼","해외세일즈","바이어매칭"}', '해외 전시 참가·글로벌 쇼룸 입점 등 B2B 마케팅 비용 지원 (브랜드별 한도 미확인)', null, '2026-04-13', '2026-05-06', '연 1회', 'https://www.koreafashion.org', '2026-06-13', 'needs_review', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "2026 K-섬유패션 글로벌 브랜드 육성 통합공고(4/13~5/6, 종료)의 글로벌 전시/B2B2C 마케팅 트랙. 브랜드별 한도는 한국패션산업협회(02-528-0108) 공고 확인."}'::jsonb),
  ('kfa-all-in-korea-2025', 'All in Korea (K-섬유패션 스트림 글로벌 브랜드 육성)', '산업통상자원부', '한국패션산업협회(KFA)', '{"디자인개발","해외수출"}', '{"기업브랜드","디자이너"}', 'K-브랜드·K-소재·K-생산이 모두 국내 업체로 구성된 컨소시엄을 대상으로 시제품·패턴·소재 개발 및 국내외 마케팅 비용을 지원하는 국내 공급망 기반 사업. 전년도 10개 브랜드 약 75억원 수출.', '{"현금","전시·쇼","해외세일즈"}', '시제품·패턴·소재 개발 및 국내외 마케팅 비용 지원 (컨소시엄별 한도 미확인)', null, '2026-04-13', '2026-05-06', '연 1회', 'https://www.koreafashion.org', '2026-06-13', 'needs_review', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "2026 K-섬유패션 글로벌 브랜드 육성 통합공고(4/13~5/6, 종료)의 한 트랙. K-브랜드·K-소재·K-생산 100% 국내 업체 컨소시엄 필수. 컨소시엄별 금액은 한국패션산업협회 공고 확인."}'::jsonb),
  ('kfa-k-fashion-audition-2025', 'K-패션오디션 (대한민국패션대전)', '산업통상자원부', '한국패션산업협회(KFA)', '{"디자인개발","국내성장","해외수출"}', '{"디자이너","기업브랜드"}', '유망 패션 브랜드와 신인 디자이너를 발굴·육성하는 경진 사업. 챌린저(론칭 7년 이하 브랜드)·비기너(학생·예비창업자) 부문 운영. 수상 브랜드에 비즈니스 바우처를 지급해 시제품·마케팅·해외진출·디지털 전환에 사용.', '{"현금","바우처","해외세일즈"}', '총 8,200만원 비즈니스 바우처. 챌린저 대상 3,000만원~장려상 200만원, 비기너 은상 1,000만원~장려상 200만원', 30000000, '2025-03-05', '2025-04-09', '연 1회', 'https://kfashionawards.org/awards/info.php', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": 7, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "챌린저: 론칭 7년 이하 국내 패션기업, 국세·지방세 완납. 비기너: 패션 관련 학생 또는 졸업 후 5년 이내 예비창업자. max_years=7은 챌린저 기준. 해외진출은 바우처 사용처 중 하나."}'::jsonb),
  ('kofoti-texworld-paris-koreapavilion-2025fw', 'Texworld Paris 한국관 참가기업 모집', '산업통상자원부', '한국섬유산업연합회(KOFOTI) / KOTRA', '{"해외수출","전시박람회"}', '{"기업브랜드"}', '프랑스 파리 텍스월드(프리미에르비종 그룹) 전시회에 한국관을 구성하고 국내 섬유·의류 기업의 부스임차료·장치비 등을 국고로 지원하는 해외전시회 참가지원 사업.', '{"전시·쇼","해외세일즈","바이어매칭"}', '부스임차료·장치비 70% 이내 국고지원, 디렉토리 제작비 100%, 운송비 1부스 1CBM 편도 100%(해상). 기업부담 약 550만원(12㎡)', null, '2025-04-17', '2025-04-25', '연 2회 (춘계/추계)', 'https://www.previewinseoul.com/fairBbs.do?selAction=view&FAIRMENU_IDX=3473&BOARD_IDX=61375&hl=KOR', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "한국 섬유·의류 기업, 주최측 사전 샘플심사 통과 + buyKOREA 상품등록 필요. 소재·원단 중심 전시회로 완제품 디자이너 브랜드 적합성 사전 확인 권장."}'::jsonb),
  ('kofoti-texworld-nyc-koreapavilion-2025', 'Texworld NYC 한국관 참가기업 모집 (수출컨소시엄)', '산업통상자원부', '한국섬유산업연합회(KOFOTI)', '{"해외수출","전시박람회"}', '{"기업브랜드"}', '미국 뉴욕 텍스월드 섬유 전시회에 한국관(수출컨소시엄)을 구성해 국내 섬유·의류 기업의 미국 시장 진출과 바이어 발굴을 지원.', '{"전시·쇼","해외세일즈","바이어매칭"}', null, null, null, null, '연 2회 (춘계/추계)', 'https://www.previewinseoul.com/fairBbs.do?selAction=view&FAIRMENU_IDX=3473&BOARD_IDX=59780&hl=KOR', '2026-06-13', 'needs_review', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "2026 NYC 한국관은 KOFOTI 자체 기획·운영으로 국고지원 대상이 아니었을 가능성(춘계 24개사 참가). ''수출컨소시엄/국고지원'' 전제 재확인 필요. 국고 70% 지원되는 Texworld Paris(별도 항목)와 혼동 주의."}'::jsonb),
  ('kotra-global-designer-fashion-logistics-2025', 'KOTRA 글로벌 디자이너 패션 물류지원 특화사업', '산업통상자원부', 'KOTRA', '{"해외수출"}', '{"디자이너","기업브랜드"}', '프리미엄 소비재 수출 확대를 위해 국내 중소·중견 패션기업(의류·액세서리·패션잡화)에 뉴욕·도쿄·방콕·상하이 거점의 3PL 공동물류를 지원.', '{"해외세일즈","공간"}', '뉴욕·도쿄·방콕·상하이 거점 공동물류(3PL) 지원 (금액 미확인)', null, '2025-03-11', '2025-09-30', '연중 (기간 내)', 'https://www.kotra.or.kr/subList/20000020753/subhome/bizAply/selectBizMntInfoDetail.do?dtlBizId=CBOTLS25031000000002&cpbizYn=N', '2026-06-13', 'confirmed', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "의류·액세서리·패션잡화 기업, KOTRA 일반회원. 금액·자부담률은 안내문 또는 02-3460-7428 확인."}'::jsonb),
  ('domestic-to-export-2025', '내수기업 수출기업화 사업', '산업통상자원부', 'KOTRA / 한국무역협회', '{"해외수출"}', '{"기업브랜드"}', '수출 실적이 없는 내수기업·초보기업에 수출전문위원 1:1 매칭, 멘토링, 화상상담회, 해외마케팅 등 수출 전 과정 컨설팅을 제공해 수출기업 전환을 지원. 처음 해외 진출하는 패션 브랜드에 적합.', '{"컨설팅","교육","바이어매칭","해외세일즈"}', null, null, '2026-01-02', '2026-03-31', '연 1회 (예산 소진 시 조기 종료)', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000103654', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중소·중견 제조/제조관련서비스/지식기반서비스업. 직수출실적 2025년 1천불 미만(내수)~10만불(초보) 대상이라 무실적도 신청 가능. 수출 전과정 컨설팅·바우처. 산업부 공고 2026-003호, KITA/KOTRA 신청."}'::jsonb),
  ('global-strong-smb-1000-2025', '글로벌 강소기업 1,000+ 프로젝트', '중소벤처기업부', '중소벤처기업진흥공단(KOSME)', '{"해외수출","국내성장"}', '{"기업브랜드"}', '성장 가능성이 높은 수출 중소기업을 수출선도기업으로 육성. 수출바우처 자동 선정, 수출지원사업 우대, 수출보증·보험 우대, 금리·환거래 우대 등 패키지 제공. 수출 실적을 갖춘 패션 브랜드의 확장 단계에 적합.', '{"바우처","해외세일즈","컨설팅"}', '직접 현금이 아닌 수출바우처 자동선정 등 우대 패키지', null, '2025-01-07', '2025-01-23', '연 1회', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000103399', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": true, "region": ["전국"], "notes": "전년 수출실적 10만 불 이상. 단계: 유망(10~100만불)·성장(100~500만불)·강소(500~1,000만불). 수출 실적 요건 명확. 2026 별도 모집."}'::jsonb),
  ('export-consortium-2025', '수출컨소시엄 사업', '중소벤처기업부', '중소기업중앙회 등 업종별 단체', '{"해외수출","전시박람회"}', '{"기업브랜드"}', '중소기업들이 컨소시엄을 구성해 해외전시회·수출상담회 등에 공동 참여하며 신시장을 개척. 사전 시장조사·현지 파견·사후관리 3단계로 진행하며 공통비용 일부를 지원. 단독 진출이 부담스러운 패션 브랜드의 공동 진출에 적합.', '{"전시·쇼","바이어매칭","해외세일즈"}', '해외시장개척 공통비용 약 70% 지원', null, null, null, '2026 전시회별 수시 (2~12월)', 'https://www.sme-expo.go.kr', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중기부 2026 통합공고 포함. 중소기업 해외전시포털 모집. 사전준비·현지파견·사후관리 공통비용 최대 70%. 업종별 협단체 주관(중기중앙회 02-2124-3291)."}'::jsonb),
  ('global-business-center-gbc-2025', '글로벌비즈니스센터(GBC) 입주기업 모집', '중소벤처기업부', '중소벤처기업진흥공단(KOSME)', '{"해외수출"}', '{"기업브랜드"}', '해외 14개국 21개소 현지 거점에 사무공간(독립실·공유오피스)을 제공하고 바이어 매칭, 인·허가·인증, 현지화 멘토링을 지원해 해외 현지 정착을 도움. 현지 거점이 필요한 패션 브랜드에 적합.', '{"공간","바이어매칭","컨설팅","해외세일즈"}', '현지 임차료 1년차 80%·2년차 50% 지원(독립 사무공간+공용회의실, 최대 3년)', null, null, null, '상시', 'https://www.kosmes.or.kr/nsh/SH/SBI/SHSBI101M0.do', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중진공(KOSME) 운영, 14개국 22개 도시. 해외진출 희망 중소기업. 상시 모집."}'::jsonb),
  ('ecommerce-export-global-mall-2025', '전자상거래수출시장진출 (글로벌쇼핑몰 활용 판매지원)', '중소벤처기업부', '중소벤처기업진흥공단(KOSME)', '{"해외수출"}', '{"기업브랜드"}', '아마존·쇼피·올리브영글로벌 등 글로벌 온라인 쇼핑몰 활용 해외 판매를 지원. 수행기관 계정 위탁판매, 자사 계정 직접 입점, 미디어콘텐츠 온라인 마케팅 중 선택 지원. 온라인 판로를 넓히려는 패션·잡화 브랜드에 적합.', '{"해외세일즈","컨설팅","교육","바이어매칭"}', '소요경비 약 60~70% 지원(자사몰·공동물류 최대 70%)', null, '2025-04-11', '2025-04-25', '연 복수 차수', 'https://www.bizinfo.go.kr/sii/siia/selectSIIA200Detail.do?pblancId=PBLN_000000000107687', '2026-06-13', 'needs_review', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "아마존·쇼피 등 글로벌쇼핑몰 입점(패션 적용 가능). 2026 운영 확인, 수행기관 모집 ~2/27. 참여기업 접수일·지원율(%)은 2026 공고 본문 확인 필요."}'::jsonb),
  ('brand-k-2025', '브랜드K 육성·관리 사업', '중소벤처기업부', '중소벤처기업유통원 / 판판대로', '{"해외수출","국내성장"}', '{"기업브랜드"}', '브랜드 파워가 약해 저평가된 우수 중소기업 제품을 발굴해 국가대표 공동브랜드 ''브랜드K''를 부여하고 국내외 마케팅·판로·해외 진출을 지원. 뷰티·리빙·푸드가 주 대상이며 패션·잡화 소비재도 신청 가능성 있음.', '{"해외세일즈","전시·쇼","컨설팅","교육"}', '브랜드K 로고 사용권 부여 및 국내외 판로·마케팅 지원(직접 현금 아님)', null, null, null, '연 1회 (별도 공지)', 'https://www.brandk.kr/join/process', '2026-06-13', 'needs_review', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "국내 중소기업, B2C 소비재(Made in Korea). ⚠️2024~2026 신규 모집 공고 미확인(최신 2023) — 폐지/통합/이관 가능성, 운영기관 직접 확인 필요. 공식 분야(뷰티·푸드·리빙 등)에 패션 명시 없음 — 패션·잡화 적용여부 불확실. 직접 현금 아님(로고 사용권+판로·홍보)."}'::jsonb),
  ('sba-export-promising-company-2025', '수출유망기업 육성지원사업 (서울)', '서울경제진흥원(SBA)', null, '{"해외수출"}', '{"기업브랜드"}', '서울 소재 수출 중소기업에 해외전시회, 해외규격인증, 통번역, 홍보·마케팅, 디자인 제작, 현지등록, 해외영업, 물류비, 통상컨설팅 등 9개 분야 수출비용을 바우처로 지원. 전년 직접수출액 기준 스케일업/초보 구분.', '{"바우처","현금","전시·쇼","해외세일즈","컨설팅"}', '스케일업(직접수출 10만불 이상) 2,000만원 10개사·1,000만원 30개사, 초보(10만불 미만) 500만원 20개사', 20000000, '2025-04-04', '2025-04-21', '연 1회 (연초)', 'https://www.sba.seoul.kr/Pages/CustomerCenter/NoticeDetail.aspx?id=e960c742-1811-f011-b403-d4f5ef4a1e33', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": true, "region": ["서울"], "notes": "서울 소재 수출 중소기업. 패션 전용은 아니나 자체 브랜드 패션·잡화 기업 신청 가능. 업종 제한·직접수출액 증빙은 원문 확인."}'::jsonb),
  ('sba-overseas-online-market-2026', '해외 온라인 시장 진출 지원사업 (서울)', '서울경제진흥원(SBA)', null, '{"해외수출"}', '{"기업브랜드"}', '서울 소재 자체 브랜드 보유 중소기업의 해외 온라인 시장 진출을 지원. 6개 권역·9개 플랫폼(아마존, 틱톡샵, 큐텐재팬, 라쿠텐, 쇼피, 샤오훙수 등) 입점·판매를 돕고 초보·고급 트랙 운영, 복수 플랫폼 동시 신청 가능.', '{"해외세일즈","컨설팅","현금"}', '9개 글로벌 플랫폼(아마존·틱톡샵·큐텐·라쿠텐·쇼피·샤오홍슈 등) 입점·광고·인플루언서·콘텐츠·라이브커머스 솔루션(현물)', null, null, '2026-04-08', '연 1회 (연초)', 'https://www.sba.seoul.kr', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["서울"], "notes": "서울 소재 자체브랜드 보유 중소기업. 2026 참여기업 840개사 공개모집(~4/8). 업종 제한 명시 없어 패션·잡화 적용 가능."}'::jsonb),
  ('kidp-design-market-pioneer-2025', '디자인 시장개척단', '한국디자인진흥원(KIDP)', null, '{"해외수출","전시박람회"}', '{"디자이너","기업브랜드"}', '수출 잠재력이 높은 디자인 기업을 선발해 미국(샌프란시스코 디자인위크)·유럽(독일 IFA)·중국(캔톤페어) 등 현지 시장에 파견. 비즈니스 상담회, 네트워킹, 디자인 쇼케이스, 수출교육, 통역 제공.', '{"전시·쇼","바이어매칭","해외세일즈","교육","컨설팅"}', null, null, '2025-02-24', '2025-03-19', '연 1회', 'https://www.kidp.or.kr', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "디자인전문회사 또는 자체 개발 제품 수출 기업, 디자인사업자 등록 요건. 패션·잡화 적용 가능하나 분야 범위·자부담률은 원문 확인. KIDP 글로벌사업실 031-780-2157."}'::jsonb),
  ('gbsa-global-ip-star-export-2025', '글로벌 IP스타기업 육성 (IP기반 해외진출지원)', '경기도', '경기도경제과학진흥원(GBSA)', '{"해외수출","디자인개발"}', '{"기업브랜드"}', '경기도 소재 수출(예정) 중소기업의 IP 기반 해외진출을 종합 지원. 제품·포장·화상 디자인 개발, 디자인 목업, 브랜드 개발, 해외진출 디자인 전략을 지원.', '{"디자인개발","컨설팅","현금"}', '연 최대 7,000만원, 3년 최대 2억 1,000만원', 70000000, '2026-01-12', '2026-02-19', null, 'https://www.bizinfo.go.kr/sii/siia/selectSIIA200Detail.do?pblancId=PBLN_000000000103441', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["경기"], "notes": "경기도 본사(남부/북부 센터 구분) 유망 중소기업, 수출실적 보유 또는 수출예정. 특허·상표·디자인 IP 기반 해외진출. 경기TP 운영."}'::jsonb),
  ('gyeonggi-textile-fashion-eco-cert-2025', '경기도 섬유·패션 친환경 글로벌 인증 지원사업', '경기도', '한국섬유소재연구원', '{"해외수출"}', '{"기업브랜드"}', '해외시장 진출에 필요한 친환경 글로벌 인증을 준비하는 경기도 소재 섬유·패션 기업에 컨설팅과 인증 획득 비용을 지원.', '{"컨설팅","현금"}', null, null, null, null, null, 'https://www.gti.re.kr', '2026-06-13', 'needs_review', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["경기"], "notes": "경기도 내 본사 또는 공장 소재 섬유·패션 기업. 운영 한국섬유소재연구원. 친환경 글로벌 인증(OEKO-TEX·GRS·GOTS·bluesign 등) 취득 지원. 2025 접수 4월. 2026 정확 일정·기업당 금액(과거 ~1,500만원 언급)은 공고 본문 확인."}'::jsonb),
  ('busan-local-industry-fashion-2025', '시군구 연고산업 육성 (부산 패션 해외진출)', '중소벤처기업부 / 부산광역시', '부산테크노파크 / 부산섬유패션산업연합회', '{"전시박람회","해외수출"}', '{"디자이너"}', '부산 지역 디자이너 브랜드의 국내외 패션 전시 참가와 해외 판로 개척을 지원하는 지역연고산업 육성사업. 패션코드·트렌드페어·부산패션위크 참가 및 ''부산쇼룸'' 공동 브랜드 운영으로 바이어 네트워크 구축.', '{"전시·쇼","공간","바이어매칭"}', null, null, null, null, null, 'http://www.fetv.co.kr/news/articleView.html?idxno=207614', '2026-06-13', 'needs_review', true, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["부산"], "notes": "부산섬유패션산업연합회 운영(부산 동구·금정구 패션 거점). 2개년 사업으로 2025년(2차년도) 12월 종료. 2026 지속/재공모 여부 불명. 문의 051-744-6321."}'::jsonb),
  ('kidp-design-led-manufacturing-innovation-2025', '디자인주도 제조혁신사업 (수요맞춤 디자인개발)', '산업통상자원부', '한국디자인진흥원(KIDP)', '{"디자인개발","국내성장"}', '{"기업브랜드"}', '중소·중견 제조기업이 디자인전문기업과 협업해 제품 디자인을 개발하고 홍보·마케팅·인프라 활용을 지원받는 사업. 패션·잡화 제조 브랜드의 제품 디자인 고도화에 활용 가능.', '{"현금","컨설팅","시제품"}', '1개 과제당 최대 3천만원 차등 지원', 30000000, '2025-02-21', '2025-03-31', '연 1회', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000105283', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중소·중견 제조기업 및 디자인전문기업. 패션/잡화 제조업 해당 여부·업종코드는 연도별 공고 확인. 2026 공고 여부 미확인."}'::jsonb),
  ('kidp-design-industry-tech-development-rnd-2025', '디자인산업기술개발사업 (디자인혁신역량강화 R&D)', '산업통상자원부', '한국산업기술기획평가원(KEIT)', '{"R&D","디자인개발"}', '{}', '디자인 혁신역량 강화를 위한 정부 R&D 과제. 기업·대학·연구기관이 디자인 관련 기술개발 연구비를 지원받음. 디자인 기반 제품·소재 개발 패션기업이 컨소시엄으로 참여 가능.', '{"R&D","현금"}', '제1차 공고 총예산 약 113억원(과제별 차등)', null, '2025-02-12', '2025-03-14', '연 복수 차수', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000104790', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "기업·대학·연구기관·연구조합 신청 가능. 과제당 지원금·기간·RFP는 차수별 공고 확인. 패션 직접 관련 과제 여부는 RFP 품목 확인."}'::jsonb),
  ('kidp-good-design-gd-selection-2025', '우수디자인(GD) 상품선정', '산업통상자원부', '한국디자인진흥원(KIDP)', '{"디자인개발","전시박람회"}', '{"디자이너","기업브랜드"}', '디자인이 우수한 상품에 정부 인증 GD(Good Design) 마크를 부여. 선정 시 GD/호주 GDA 마크 사용, 조달 우수제품 가점, 특허청 디자인등록출원 우선심사 가점 등 혜택.', '{"IP","컨설팅"}', '현금성 지원 없음(인증·마크 부여형)', null, '2025-05-01', '2025-06-30', '연 1회', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000104970', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["개인", "법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "상품 소유권 보유 기업 또는 디자인개발기업. 신청일 기준 2년 전부터 판매 중/예정 상품. 출품료 유무는 공고 확인. 패션·잡화 부문 출품 가능."}'::jsonb),
  ('kidp-design-firm-fostering-globalization-2025', '디자인전문기업육성 및 글로벌화 (육성부문)', '산업통상자원부', '한국디자인진흥원(KIDP)', '{"디자인개발","국내성장"}', '{"기업브랜드"}', '디자인전문기업의 역량 육성과 시장 경쟁력 창출을 지원하는 사업. 패션·디자인 분야 디자인전문기업 성장 지원에 해당 가능.', '{"컨설팅","현금"}', null, null, null, null, '연 1회', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000105217', '2026-06-13', 'needs_review', false, '{"min_years": null, "max_years": null, "biz_type": ["법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "산업디자인전문회사 신고기업 대상 추정(패션 디자인전문기업 신고 시 적용 가능성). 2026 공고 게시(KIDP 2026-20호). 자격·금액·일정 본문 확인 필요."}'::jsonb),
  ('kidp-sustainable-design-support-2025', '지속가능디자인지원사업', '산업통상자원부', '한국디자인진흥원(KIDP)', '{"디자인개발","R&D","국내성장"}', '{"기업브랜드"}', '서비스디자인을 활용해 기업의 제품·서비스·비즈니스모델을 고도화·혁신하도록 지원. 중소·중견기업과 디자인전문기업이 컨소시엄으로 신청.', '{"현금","컨설팅"}', '1개 컨소시엄당 최대 약 4억5천만원 규모', 450000000, '2025-05-12', '2025-06-05', '연 1회', 'https://www.bizinfo.go.kr/web/lay1/bbs/S1T122C128/AS/74/view.do?pblancId=PBLN_000000000105148', '2026-06-13', 'confirmed', false, '{"min_years": null, "max_years": null, "biz_type": ["법인"], "max_revenue": null, "export_required": false, "region": ["전국"], "notes": "중소·중견기업+디자인전문기업 컨소시엄. 지원금 상한은 요약 기반(약 4.5억) — 공고로 재확인. 패션 단독보다 컨소시엄 적합."}'::jsonb),
